var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"으음~. 잘 잤다.","JPN":"うーん、よく寝た。","ENG":"Mmm... I feel so rested.","TWN":"嗯嗯～睡得真好。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"피곤해서 그런가? 평소보다 푹 잔 것 같은 기분인데?","JPN":"疲れていたからかな？　いつもよりぐっすり寝た気がする。","ENG":"Maybe I was more tired than I thought? Feels like I slept way better than usual.","TWN":"是因為累了嗎？感覺比平時睡得更沉呢？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"으으…….","JPN":"うう……","ENG":"Uuugh...","TWN":"嗚嗚……"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"에리어스, 왜 그래? 어디 아파?","JPN":"アリウス、どうしたの？　体調悪いとか？","ENG":"Arius? What's wrong? Are you sick?","TWN":"埃里奧斯，怎麼了？哪裡不舒服嗎？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"그야 리브 경의 잠꼬대가 밤새도록 이어졌으니 그렇죠.","JPN":"リブ卿の寝言がひどかったからでしょう。","ENG":"Well, you were talking in your sleep all night, Dame Liv.","TWN":"是因為莉芙整晚一直在說夢話吧。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"아마 여기서 푹 잔 사람은 리브 경밖에 없을 걸요.","JPN":"たぶんここでぐっすり寝た人なんて、リブ卿しかないはずです。","ENG":"Pretty sure you're the only one who got any real rest.","TWN":"恐怕在這裡睡得好的只有莉芙吧。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"으응? 이상하네. 공기가 좋아서 몸이 풀어졌나?","JPN":"え～？　おかしいな。空気がキレイで体がほぐれたのかな？","ENG":"Huh? Weird. Maybe the fresh country air relaxed me?","TWN":"呃嗯？奇怪了。是不是因為空氣好，身體放鬆了呢？"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"시골, 무섭다!","JPN":"田舎、怖い！","ENG":"Countryside... kinda scary!","TWN":"鄉下，好可怕！"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"본부 복귀 이전, 고향에 들리고 싶다는 단장님의 말에.","JPN":"本部に復帰する前、故郷を訪問したいという団長の話に。","ENG":"And to think, who was it that said she couldn't sleep unless it was in a fluffy bed,","TWN":"在返回總部之前，團長說想回故鄉看看。"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"푹신한 침대가 아니면 잘 수 없다고 말한 사람이 누구였죠?","JPN":"ふわふわのベッドじゃないと眠れないって言った人、どこの誰でしたっけ？","ENG":"right before Captain said she wanted to stop by her hometown?","TWN":"說過沒有柔軟的床就睡不著的人是誰呢？"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"헤헤. 그만큼 열심히 싸웠다는 거 아니겠어?","JPN":"へへ。それくらい頑張って戦ったってことじゃないの？","ENG":"Hehe, that just proves how hard I've been fighting!","TWN":"嘿嘿，這說明我拼命戰鬥了，對吧？"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그런데 다른 사람들은?","JPN":"ところで、他のみんなは？","ENG":"Anyway, where is everyone?","TWN":"其他人呢？"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"단장님이라면 아침 일찍 볼일이 있다면서 나가셨어요. 부단장님은 단장님을 따라갔고요.","JPN":"団長なら朝早く用事があるからと出て行かれました。副団長は団長について行きましたし。","ENG":"Captain left early. Said she had something to do. Deputy Fione went with her.","TWN":"團長說早上有事要辦，已經出去了。副團長也跟著團長一起去了。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"헉. 이번엔 단장이랑 부단장이 손잡고 사라지는 거 아니야?!","JPN":"はっ。今度は団長と副団長と一緒に消えるんじゃない！？","ENG":"*Gasp* Don't tell me they ran off together, hand in hand?!","TWN":"哎呀。這次不會是團長和副團長聯手消失吧？！"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"리브 언니… 그건 제가 생각해도 이상해요.","JPN":"リブさん……それは私が考えても変ですよ。","ENG":"Liv... Even I think that sounds weird.","TWN":"莉芙姊姊……那個我也覺得很奇怪。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"아, 역시 글치?","JPN":"あ、やっぱりそう？","ENG":"Right?","TWN":"啊，果然是吧？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"다들 일어나셨군요.","JPN":"皆さん、おはようございます。","ENG":"Ah, you're all awake.","TWN":"大家都醒過來了啊。"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"아침 준비가 되었습니다만, 식사는 어떻게 하시겠습니까?","JPN":"朝食の準備ができましたが、どうなさいますか？","ENG":"Breakfast is ready. Would you like to eat now?","TWN":"早餐已經準備好了，你打算怎麼用餐？"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"야호! 밥이다, 밥! 오늘의 메뉴는 뭔가요, 촌장님?","JPN":"やっほー！　ご飯だ、ご飯！　今日のメニューはなんですか、村長？","ENG":"Woohoo! Food! What's for breakfast, Chief?","TWN":"耶！吃飯了！今天的菜色是什麼，村長？"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"실례예요, 리브 경. 거기에 다른 분들도 돌아오지 않으셨잖아요.","JPN":"失礼ですよ、リブ卿。それに、団長と副団長がまだ帰ってきてないです。","ENG":"Excuse me, Dame Liv, but the others aren't back yet.","TWN":"失禮了，莉芙。其他人也沒有回來。"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"음? 아직 에스테로사가 돌아오지 않은 겁니까?","JPN":"おや？　エステロサはまだ帰っていないのですか？","ENG":"Hmm? So Esterosa hasn't returned either?","TWN":"嗯？艾斯特洛索還沒回來嗎？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"촌장님은 뭔가 알고 계신 게 있나요?","JPN":"村長は何かご存じなんですか？","ENG":"Chief, do you know something about where she went?","TWN":"村長你知道些什麼嗎？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"나이가 들면 새벽부터 움직이는 법이니까요. 그 아이가 간 곳이라면 이야기를 들었습니다.","JPN":"老人になると朝早くから動くようになりますからね。あの子が向かった場所なら、聞いています。","ENG":"Well, old folks like me tend to get moving early. I heard where she went.","TWN":"年紀大了就會從淩晨開始行動。關於那個孩子去的地方，我已經聽說了。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"여러분이 괜찮으시다면 에스테로사가 있는 장소를 알려드리죠.","JPN":"皆さんがよろしければエステロサの居場所を教えましょう。","ENG":"If you're up for it, I can tell you where she is.","TWN":"如果你們沒問題的話，我會告訴你們艾斯特洛索所在的地方。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};